# ── 5. Language switching (optional — for multi-language hubs) ────────────────
"""
# urls.py
from django.conf.urls.i18n import i18n_patterns

urlpatterns += i18n_patterns(
    path("", include("apps.core.urls")),
    prefix_default_language=False,  # /de/... and /... (not /en/...)
)

# Template language switcher:
{% load i18n %}
{% get_available_languages as LANGUAGES %}
{% get_current_language as LANGUAGE_CODE %}

<nav aria-label="{% trans 'nav.settings' %}" class="flex gap-2">
    {% for lang_code, lang_name in LANGUAGES %}
        {% language lang_code %}
        <a href="{{ request.path }}"
           class="text-sm {% if lang_code == LANGUAGE_CODE %}text-primary font-medium{% else %}text-muted{% endif %}
                  pui-interactive">
            {{ lang_code|upper }}
        </a>
        {% endlanguage %}
    {% endfor %}
</nav>
"""
